import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import Modal from "../components/Modal";

function Admin() {
  const [teachers, setTeachers] = useState([]);
  const [students, setStudents] = useState([]);
  const [courses, setCourses] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemToBanOrDelete, setItemToBanOrDelete] = useState(null);
  const [actionType, setActionType] = useState("");
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();

  useEffect(() => {
    if (!user || user.role !== "admin") {
      navigate("/dashboard");
    }
    fetch("http://localhost:3001/users?role=teacher")
      .then((res) => res.json())
      .then((data) => setTeachers(data))
      .catch((error) => toast.error("Ошибка загрузки преподавателей"));
    fetch("http://localhost:3001/users?role=student")
      .then((res) => res.json())
      .then((data) => setStudents(data))
      .catch((error) => toast.error("Ошибка загрузки студентов"));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data))
      .catch((error) => toast.error("Ошибка загрузки курсов"));
  }, [user, navigate]);

  async function handleBanUser() {
    try {
      const userToBan = [...teachers, ...students].find((u) => u.id === itemToBanOrDelete);
      if (!userToBan) {
        toast.error("Пользователь не найден");
        return;
      }
      const updatedUser = { ...userToBan, isBanned: true };
      const response = await fetch(`http://localhost:3001/users/${itemToBanOrDelete}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedUser),
      });
      if (response.ok) {
        setTeachers(teachers.map((t) => (t.id === itemToBanOrDelete ? updatedUser : t)));
        setStudents(students.map((s) => (s.id === itemToBanOrDelete ? updatedUser : s)));
        toast.success("Пользователь забанен!");
      } else {
        toast.error("Не удалось забанить пользователя");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при бане");
    }
    setIsModalOpen(false);
  }

  async function handleDeleteCourse() {
    try {
      const response = await fetch(`http://localhost:3001/courses/${itemToBanOrDelete}`, {
        method: "DELETE",
      });
      if (response.ok) {
        setCourses(courses.filter((c) => c.id !== itemToBanOrDelete));
        toast.success("Курс удален!");
      } else {
        toast.error("Не удалось удалить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении курса");
    }
    setIsModalOpen(false);
  }

  function openModal(id, type) {
    setItemToBanOrDelete(id);
    setActionType(type);
    setIsModalOpen(true);
  }

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6 text-gray-800">Панель администратора</h1>

      <h2 className="text-2xl font-semibold mb-4 text-gray-700">Преподаватели</h2>
      <ul className="space-y-4">
        {teachers.map((teacher) => (
          <li key={teacher.id} className="bg-white p-4 rounded-lg shadow-md flex justify-between items-center">
            <span>
              {teacher.name} ({teacher.email}) {teacher.isBanned && <span className="text-red-600">[Забанен]</span>}
            </span>
            {!teacher.isBanned && (
              <button
                onClick={() => openModal(teacher.id, "banUser")}
                className="bg-red-600 text-white py-1 px-3 rounded-md hover:bg-red-700 transition"
                aria-label={`Забанить ${teacher.name}`}
              >
                Забанить
              </button>
            )}
          </li>
        ))}
      </ul>

      <h2 className="text-2xl font-semibold mb-4 mt-8 text-gray-700">Студенты</h2>
      <ul className="space-y-4">
        {students.map((student) => (
          <li key={student.id} className="bg-white p-4 rounded-lg shadow-md flex justify-between items-center">
            <span>
              {student.name} ({student.email}) {student.isBanned && <span className="text-red-600">[Забанен]</span>}
            </span>
            {!student.isBanned && (
              <button
                onClick={() => openModal(student.id, "banUser")}
                className="bg-red-600 text-white py-1 px-3 rounded-md hover:bg-red-700 transition"
                aria-label={`Забанить ${student.name}`}
              >
                Забанить
              </button>
            )}
          </li>
        ))}
      </ul>

      <h2 className="text-2xl font-semibold mb-4 mt-8 text-gray-700">Курсы</h2>
      <ul className="space-y-4">
        {courses.map((course) => (
          <li key={course.id} className="bg-white p-4 rounded-lg shadow-md flex justify-between items-center">
            <span>
              {course.name} - {course.description}
            </span>
            <div className="flex gap-2">
              <Link to={`/edit-course/${course.id}`}>
                <button
                  className="bg-yellow-500 text-white py-1 px-3 rounded-md hover:bg-yellow-600 transition"
                  aria-label={`Редактировать ${course.name}`}
                >
                  Редактировать
                </button>
              </Link>
              <button
                onClick={() => openModal(course.id, "deleteCourse")}
                className="bg-red-600 text-white py-1 px-3 rounded-md hover:bg-red-700 transition"
                aria-label={`Удалить ${course.name}`}
              >
                Удалить
              </button>
            </div>
          </li>
        ))}
      </ul>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={actionType === "banUser" ? handleBanUser : handleDeleteCourse}
        message={
          actionType === "banUser"
            ? "Вы уверены, что хотите забанить этого пользователя?"
            : "Вы уверены, что хотите удалить этот курс?"
        }
      />
    </div>
  );
}

export default Admin;
